import com.pinterest.ktlint.core.RuleProvider
import com.pinterest.ktlint.ruleset.standard.TrailingCommaOnDeclarationSiteRule.Companion.TRAILING_COMMA_ON_DECLARATION_SITE_PROPERTY
import com.pinterest.ktlint.test.KtLintAssertThat
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

/**
 * Tests for the specific issue where formatting enum class with member definition 
 * and missing trailing commas causes rule violations on first run.
 * 
 * See issue: https://github.com/pinterest/ktlint/issues/1709
 */
class TrailingCommaOnDeclarationSiteRuleIssueTest {
    private val trailingCommaOnDeclarationSiteRuleAssertThat =
        KtLintAssertThat.assertThatRule(
            provider = { TrailingCommaOnDeclarationSiteRule() },
            additionalRuleProviders = setOf(
                // WrappingRule must be loaded in order to run TrailingCommaOnDeclarationSiteRule
                RuleProvider { WrappingRule() },
                // Apply the IndentationRule always as additional rule
                RuleProvider { IndentationRule() },
                // Include NoSemicolonsRule to verify no conflict
                RuleProvider { NoSemicolonsRule() },
            ),
        )

    @Test
    fun `Issue 1709 - Given enum class with member definition and missing trailing comma then format correctly without errors`() {
        val code =
            """
            enum class TestEnum() {
                A,
                B;

                companion object {
                    const val A_NUMBER = 1L
                }
            }
